<?php declare(strict_types=1); namespace Database\Factories\FarmDirect; use App\Domains\FarmDirect\Models\FarmDirect; use Illuminate\Database\Eloquent\Factories\Factory; final class FarmDirectFactory extends Factory { protected $model = FarmDirect::class; public function definition(): array { return ['name' => $this->faker->words(2, true), 'sku' => strtoupper('FARM-' . $this->faker->bothify('####')), 'product_type' => $this->faker->randomElement(['vegetables', 'fruits', 'dairy', 'meat', 'grains', 'honey']), 'farm_name' => $this->faker->company(), 'price' => $this->faker->numberBetween(30000, 200000), 'current_stock' => $this->faker->numberBetween(50, 300), 'is_organic' => $this->faker->boolean(70), 'is_local' => true, 'rating' => $this->faker->randomFloat(1, 4.0, 5), 'review_count' => $this->faker->numberBetween(20, 150), 'status' => 'active', 'correlation_id' => \Illuminate\Support\Str::uuid()->toString(), 'tags' => ['farm', 'direct', 'fresh'], 'meta' => []]; } public function organic(): self { return $this->state(['is_organic' => true]); } public function conventional(): self { return $this->state(['is_organic' => false]); } }
